**Looking at the source code, there is no support for setting multiple ranges at once at the same time. It can only be set by multiple calls. Like this:**



```
(async () => {
  const wb = new ExcelJS.Workbook();
  const ws = wb.addWorksheet('Test');

  for (let col = 1; col < 6; col++) {
    for (let row = 1; row < 6; row++) {
      const cell = ws.getCell(col, row);
      cell.value = row * col;
    }
  }
  ws.addConditionalFormatting({
    // ref: '$A$1:$E$1;$A$3:$E$3;$A$5:$E$5',
    // ref: 'A1:E1;A3:E3;A5:E5',
    ref: 'A1:E1',
    rules: [
      {
        type: 'colorScale',
        cfvo: [{ type: 'min' }, { type: 'max' }],
        color: [{ argb: 'FF77F22C' }, { argb: 'FFDA3F2A' }]
      }
    ]
  });
  ws.addConditionalFormatting({
    // ref: '$A$1:$E$1;$A$3:$E$3;$A$5:$E$5',
    // ref: 'A1:E1;A3:E3;A5:E5',
    ref: 'A3:E3',
    rules: [
      {
        type: 'colorScale',
        cfvo: [{ type: 'min' }, { type: 'max' }],
        color: [{ argb: 'FF77F22C' }, { argb: 'FFDA3F2A' }]
      }
    ]
  });
  await wb.xlsx.writeFile('testCF.xlsx');
})();
```
